<?php
declare(strict_types=1);require_once __DIR__.'/_layout.php';$pdo=obtenerConexion();docenteCabecera('Evaluaciones','evaluaciones','Evaluaciones vinculadas a cursos asignados.');$docenteId=(int)$GLOBALS['docentePortalId'];docenteSelectorSupervision($pdo);$curso=docenteId($_GET['curso']??0);if($curso)exigirCursoDocente($pdo,$docenteId,$curso);$cursos=cursosDocenteAtenea($pdo,$docenteId);$where=' WHERE e.docente_id=:d';$pa=['d'=>$docenteId];if($curso){$where.=' AND e.asignatura_id=:a';$pa['a']=$curso;}$q=$pdo->prepare("SELECT e.*,a.nombre asignatura,COUNT(ee.id) entregas,SUM(ee.estado IN('pendiente','tardia')) pendientes FROM evaluaciones e JOIN asignaturas a ON a.id=e.asignatura_id LEFT JOIN ev_entregadas ee ON ee.evaluacion_id=e.id".$where.' GROUP BY e.id ORDER BY e.created_at DESC LIMIT 100');$q->execute($pa);$filas=$q->fetchAll();?>
<?php if($docenteId&&$cursos):?><div class="card card-rounded mb-4"><div class="card-body"><h2 class="h5">Nueva evaluación</h2><form method="post" action="evaluacion_guardar.php" class="row g-3"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><div class="col-md-4"><label class="form-label">Curso</label><select class="form-select" name="asignatura_id" required><?php foreach($cursos as$c):?><option value="<?=$c['id']?>" <?=$curso===$c['id']?'selected':''?>><?=atenea_e($c['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-5"><label class="form-label">Título</label><input class="form-control" name="titulo" maxlength="190" required></div><div class="col-md-3"><label class="form-label">Nota máxima</label><input class="form-control" type="number" name="nota_maxima" min="0.01" max="1000" step="0.01" value="10.00" required></div><div class="col-12"><label class="form-label">Descripción</label><textarea class="form-control" name="descripcion" maxlength="5000"></textarea></div><div class="col-md-4"><label class="form-label">Apertura</label><input class="form-control" type="datetime-local" name="fecha_apertura"></div><div class="col-md-4"><label class="form-label">Cierre</label><input class="form-control" type="datetime-local" name="fecha_cierre"></div><div class="col-md-2"><label class="form-label">Estado</label><select class="form-select" name="estado"><option>borrador</option><option>publicada</option><option>cerrada</option><option>inactiva</option></select></div><div class="col-md-2 d-flex align-items-end"><button class="btn btn-primary w-100">Guardar</button></div></form></div></div><?php endif;?><div class="card card-rounded"><div class="card-body"><div class="table-responsive"><table class="table"><thead><tr><th>Evaluación</th><th>Curso</th><th>Fechas</th><th>Estado</th><th>Entregas</th><th></th></tr></thead><tbody><?php foreach($filas as$e):?><tr><td><?=atenea_e($e['titulo'])?><small class="d-block">Máximo: <?=atenea_e($e['nota_maxima'])?></small></td><td><?=atenea_e($e['asignatura'])?></td><td><?=atenea_e($e['fecha_apertura']?date('d/m/Y H:i',strtotime($e['fecha_apertura'])):'Sin apertura')?> → <?=atenea_e($e['fecha_cierre']?date('d/m/Y H:i',strtotime($e['fecha_cierre'])):'Sin cierre')?></td><td><form method="post" action="estado.php" class="d-flex gap-1"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="docente_id" value="<?=$docenteId?>"><input type="hidden" name="tipo" value="evaluacion"><input type="hidden" name="id" value="<?=$e['id']?>"><select class="form-select form-select-sm" name="estado" aria-label="Estado de la evaluación"><?php foreach(['borrador','publicada','cerrada','inactiva'] as$estadoOpcion):?><option value="<?=$estadoOpcion?>" <?=$e['estado']===$estadoOpcion?'selected':''?>><?=atenea_e($estadoOpcion)?></option><?php endforeach;?></select><button class="btn btn-sm btn-outline-primary">Aplicar</button><a class="btn btn-sm btn-outline-secondary" href="<?=docenteUrl('evaluacion_editar.php',['id'=>$e['id']])?>">Editar</a></form></td><td><?=(int)$e['entregas']?> · <?=(int)$e['pendientes']?> pendientes</td><td><a class="btn btn-sm btn-outline-primary" href="<?=docenteUrl('entregas.php',['evaluacion'=>$e['id']])?>">Revisar</a></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="6" class="text-center py-5">No hay evaluaciones reales registradas.</td></tr><?php endif;?></tbody></table></div></div></div><?php docentePie();
